import{c as i,Q as a,j as e,m as o}from"./chunks/framework.4b-lwRvT.js";const k=JSON.parse('{"title":"教程撰写工作流","description":"","frontmatter":{"title":"教程撰写工作流"},"headers":[],"relativePath":"workflow/tutorial-workflow.md","filePath":"workflow/tutorial-workflow.md","lastUpdated":1779684191000}'),t={name:"workflow/tutorial-workflow.md"};function r(c,l,u,d,h,n){return a(),e("div",null,[...l[0]||(l[0]=[o('<ul><li>目标：用业余时间产出高质量、小规模、可复用的教程（30–60 分钟到 2 小时的微教程，或 1–2 天的短教程）。</li><li>要求：可重复、可维护、易迭代、对读者友好（先行者/零起点两类）。</li><li>输出形式：Markdown 文档 + 代码仓（示例工程）+ 可选短视频/动图。</li></ul><h2 id="总体流程-一页版" tabindex="-1">总体流程（一页版） <a class="header-anchor" href="#总体流程-一页版" aria-label="Permalink to &quot;总体流程（一页版）&quot;">​</a></h2><ol><li>Ideas草稿预备（作为文档系列的前言教程）</li><li>定位与大纲（准备好具体的目标读者，定位和大纲编写）</li><li>编写Draft草稿和初次设计</li><li>本地验证（自己跑一遍）</li><li>邀请Peers进行阅读验证</li><li>迭代修复</li><li>发布</li><li>收集反馈并计划下个迭代</li></ol><h2 id="目前计划的workflow" tabindex="-1">目前计划的Workflow <a class="header-anchor" href="#目前计划的workflow" aria-label="Permalink to &quot;目前计划的Workflow&quot;">​</a></h2><p>（1–2 周，人均每晚 1hr + 周末 3–4hr）</p><ul><li>Day 0：确定主题与受众（30min）</li><li>Day 1：写教程大纲 + 列出必要环境和成果（1hr）</li><li>Day 3–6：撰写主体（分块完成，每晚 45–60min）</li><li>Weekend：本地验证、补充示例、生成截图/动图（4hrs）</li><li>Day 8：同伴测试与修订（1–2hrs）</li><li>Day 10：发布并发通知（1hr）</li></ul><h2 id="撰写规范-质量控制" tabindex="-1">撰写规范（质量控制） <a class="header-anchor" href="#撰写规范-质量控制" aria-label="Permalink to &quot;撰写规范（质量控制）&quot;">​</a></h2><p>预计的计划：</p><ul><li>每篇给出明确时间长度（让读者决定是否有时间）</li><li>每个关键命令必须可复制粘贴并能运行（避免&quot;概念性示例&quot;）</li><li>所有截图附带文字描述；所有图像都写 <code>alt</code> 文本</li><li>给出可运行的最小示例（MVP）和可选扩展</li><li>明确列出环境版本（避免因版本导致报错）</li><li>代码注释要足够解释&quot;为什么做这样&quot;，而非只实现</li><li>每篇至少包含 1 个练习与参考答案</li></ul><h2 id="测试与-ci-轻量级" tabindex="-1">测试与 CI（轻量级） <a class="header-anchor" href="#测试与-ci-轻量级" aria-label="Permalink to &quot;测试与 CI（轻量级）&quot;">​</a></h2><ul><li>每个 tutorial repo 含 <code>tests/quick_check.sh</code>：自动化跑最小示例并返回 0/1</li><li>CI（可选）：在 GitHub Actions 上跑 <code>quick_check</code>，确保示例不会随时间失效</li><li>PR 要求：运行 <code>quick_check</code> 并通过，reviewer 复现至少一遍教程</li></ul><h2 id="版本-分支-协作-git-工作流" tabindex="-1">版本/分支 &amp; 协作（Git 工作流） <a class="header-anchor" href="#版本-分支-协作-git-工作流" aria-label="Permalink to &quot;版本/分支 &amp; 协作（Git 工作流）&quot;">​</a></h2><ul><li>主分支：<code>main</code>（发布稳定版）</li><li>任务分支：<code>feat/tutorial-name</code> 或 <code>fix/tutorial-name</code></li><li>PR 模板（简短）： <ul><li>简述改动</li><li>如何复现（步骤）</li><li>CI 状态（quick_check）</li><li>目标受众/冲突说明</li></ul></li></ul><h2 id="发布渠道与格式-业余友好" tabindex="-1">发布渠道与格式（业余友好） <a class="header-anchor" href="#发布渠道与格式-业余友好" aria-label="Permalink to &quot;发布渠道与格式（业余友好）&quot;">​</a></h2><ul><li>文字优先：GitHub Pages、Hexo/Hugo、简书、博客园</li><li>媒体辅助：短视频（3–8 分钟）、GIF（用于演示交互步骤）</li><li>同步渠道：Twitter/X、微博、微信公众号、LinkedIn</li><li>文章首发 + 程序仓库（示例代码）双管齐下</li></ul><h2 id="检查清单-发布前必须通过" tabindex="-1">检查清单（发布前必须通过） <a class="header-anchor" href="#检查清单-发布前必须通过" aria-label="Permalink to &quot;检查清单（发布前必须通过）&quot;">​</a></h2><ul><li>[ ] 标题清晰并包含关键词</li><li>[ ] TL;DR 与目标明确</li><li>[ ] 环境/版本写明</li><li>[ ] 所有命令已在干净环境验证</li><li>[ ] 演示图片或 GIF 无缺失，且包含 <code>alt</code></li><li>[ ] 至少 1 个练习与参考解答</li><li>[ ] README 包含仓库快速运行步骤</li><li>[ ] <code>tests/quick_check.sh</code> 可以本地一键跑通</li><li>[ ] 有反馈渠道（issue/邮箱）</li></ul><h2 id="迭代范例-如何从-mvp-变成完整版" tabindex="-1">迭代范例（如何从 MVP 变成完整版） <a class="header-anchor" href="#迭代范例-如何从-mvp-变成完整版" aria-label="Permalink to &quot;迭代范例（如何从 MVP 变成完整版）&quot;">​</a></h2><p>MVP（发布后 1 周）：</p><ul><li>最小可运行示例 + 核心步骤 + 1 张演示图</li></ul><p>V1（发布后 2–4 周）：</p><ul><li>补充 2-3 个练习、增加错误排查、增加视频或 GIF</li></ul><p>V2（发布后 1–3 个月）：</p><ul><li>增加国际化（英文版）、兼容更多平台、CI 完整化</li></ul>',24)])])}const f=i(t,[["render",r]]);export{k as __pageData,f as default};
